// Unmarshal appends one row to c per entity in rec, projecting
// the runtime.facts columns through factsschema/ra. Thin wrapper
// around TaskCreatedFillFromArrow — the per-row decode lives there.
func (c *TaskCreatedColumns) Unmarshal(rec arrow.Record) (err error) {
	r := newTaskCreatedReader()
	defer r.release()
	err = r.loadFromRecord(rec)
	if err != nil {
		return
	}
	n := r.EntityId.Len()
	err = TaskCreatedFillFromArrow(
		c,
		n,
		r.EntityId.ValueId,
		r.EntityTimestamp.ValueTs,
		r.StringArray.Attributes, r.StringArray.Memberships,
		r.Symbol.Attributes, r.Symbol.Memberships,
		r.TextArray.Attributes, r.TextArray.Memberships,
		r.U64Array.Attributes, r.U64Array.Memberships,
		r.Bool.Attributes, r.Bool.Memberships,
		r.I64Array.Attributes, r.I64Array.Memberships,
	)
	return
}

// --- buscodec.CodecI bridge. ---

// TaskCreatedCodec is the buscodec.CodecI bridge for TaskCreated. Encodes one row
// through dml_cbor; decodes via cborarrow.Convert + ra-Unmarshal +
// Row(0). Auto-registered in init() so callers using buscodec.Encode
// / Decode route through here instead of the CBOR fallback.
type TaskCreatedCodec struct{}

var _ buscodec.CodecI = (*TaskCreatedCodec)(nil)

// taskCreatedBusCodec is the package-local singleton wired into buscodec.
var taskCreatedBusCodec = &TaskCreatedCodec{}

func (inst *TaskCreatedCodec) Name() (n string) {
	n = "taskCreated-sparse-cbor"
	return
}

func (inst *TaskCreatedCodec) ContentType() (ct string) {
	ct = "application/x-runtime-facts+rb;kind=taskCreated"
	return
}

func (inst *TaskCreatedCodec) Encode(v any) (b []byte, err error) {
	var row TaskCreated
	switch x := v.(type) {
	case TaskCreated:
		row = x
	case *TaskCreated:
		if x == nil {
			err = eh.Errorf("taskcreated: Encode nil *TaskCreated")
			return
		}
		row = *x
	default:
		err = eh.Errorf("taskcreated: Encode requires TaskCreated or *TaskCreated, got %T", v)
		return
	}
	cols := &TaskCreatedColumns{}
	cols.Append(row)
	var buf bytes.Buffer
	err = cols.Marshal(&buf)
	if err != nil {
		err = eh.Errorf("taskcreated: Encode marshal: %w", err)
		return
	}
	b = buf.Bytes()
	return
}

func (inst *TaskCreatedCodec) Decode(b []byte, v any) (err error) {
	target, ok := v.(*TaskCreated)
	if !ok {
		err = eh.Errorf("taskcreated: Decode requires *TaskCreated, got %T", v)
		return
	}
	var arrowBuf bytes.Buffer
	err = cborarrow.Convert(bytes.NewReader(b), &arrowBuf)
	if err != nil {
		err = eh.Errorf("taskcreated: Decode cborarrow: %w", err)
		return
	}
	rd, err := ipc.NewReader(&arrowBuf)
	if err != nil {
		err = eh.Errorf("taskcreated: Decode ipc reader: %w", err)
		return
	}
	defer rd.Release()
	if !rd.Next() {
		err = eh.Errorf("taskcreated: Decode expected one Arrow record, got none")
		return
	}
	rec := rd.RecordBatch()
	defer rec.Release()
	cols := &TaskCreatedColumns{}
	err = cols.Unmarshal(rec)
	if err != nil {
		err = eh.Errorf("taskcreated: Decode unmarshal: %w", err)
		return
	}
	if cols.Len() != 1 {
		err = eb.Build().Int("got", cols.Len()).Errorf("taskcreated: Decode expected 1 row")
		return
	}
	*target = cols.Row(0)
	return
}
